/* ── Phase helpers ── */
const IE = (i=3, e=2, iCue='Inspire — relâche le périnée', eCue='Expire — remonte le périnée') => [
  { id:'inspire', label:'INSPIRE', duration:i, scale:1.38, barDir:'fill', cue:iCue, beltLed:'#8BA7FF', beltLabel:'LED bleue' },
  { id:'expire',  label:'EXPIRE',  duration:e, scale:1.0,  barDir:'empty', cue:eCue, beltLed:'#F0A040', beltLabel:'LED orange' },
];
const IEHS = (i=2, e=2, h=2) => [
  { id:'inspire', label:'INSPIRE',  duration:i, scale:1.38, barDir:'fill',       cue:'Inspire — relâche le périnée',          beltLed:'#8BA7FF', beltLabel:'LED bleue' },
  { id:'expire',  label:'EXPIRE',   duration:e, scale:1.0,  barDir:'empty',      cue:'Expire — remonte et serre le périnée',   beltLed:'#F0A040', beltLabel:'LED orange' },
  { id:'hold',    label:'SQUEEZE',  duration:h, scale:1.0,  barDir:'hold-empty', cue:'Maintiens la contraction du périnée',    beltLed:'#F0B429', beltLabel:'LED dorée' },
];
const KEGEL = (c=3, r=3) => [
  { id:'contract', label:'CONTRACTE', duration:c, scale:1.0,  barDir:'empty',      cue:'Serre le périnée progressivement\nVers le haut et l\'intérieur', beltLed:'#F0B429', beltLabel:'LED dorée' },
  { id:'release',  label:'RELÂCHE',   duration:r, scale:1.38, barDir:'fill',       cue:'Relâche complètement\nDescente consciente du plancher pelvien',  beltLed:'#8BA7FF', beltLabel:'LED bleue' },
];
const BOX4 = () => [
  { id:'inspire',    label:'INSPIRE 4s',  duration:4, scale:1.42, barDir:'fill',       cue:'Inspire par le nez\nVentre qui se gonfle',   beltLed:'#8BA7FF', beltLabel:'LED bleue' },
  { id:'hold_full',  label:'RETIENS 4s',  duration:4, scale:1.42, barDir:'hold-full',  cue:'Retiens doucement\nCorps immobile',           beltLed:'#F0B429', beltLabel:'LED dorée' },
  { id:'expire',     label:'EXPIRE 4s',   duration:4, scale:1.0,  barDir:'empty',      cue:'Expire totalement\nPérinée qui remonte',      beltLed:'#F0A040', beltLabel:'LED orange' },
  { id:'hold_empty', label:'PAUSE 4s',    duration:4, scale:1.0,  barDir:'hold-empty', cue:'Pause vide\nRelâche tout',                    beltLed:'#4A3669', beltLabel:'LED violet' },
];
const VACUUM_P = () => [
  { id:'expire_total', label:'EXPIRE',  duration:3, scale:0.8, barDir:'empty',      cue:'Expire tout l\'air\nPoumons complètement vides',                     beltLed:'#F0A040', beltLabel:'LED orange' },
  { id:'vacuum',       label:'ASPIRE',  duration:5, scale:0.7, barDir:'hold-empty', cue:'Aspire le ventre vers l\'intérieur\nSous les côtes, périnée neutre',   beltLed:'#7B5EA7', beltLabel:'LED violette' },
  { id:'release',      label:'RELÂCHE', duration:3, scale:1.38,barDir:'fill',       cue:'Inspire et relâche\nVentre qui se gonfle naturellement',               beltLed:'#8BA7FF', beltLabel:'LED bleue' },
];
const STRETCH_P = () => [
  { id:'inspire', label:'INSPIRE', duration:4, scale:1.42, barDir:'fill',  cue:'Inspire profondément\nÉtirement qui s\'approfondit',      beltLed:'#8BA7FF', beltLabel:'LED bleue' },
  { id:'expire',  label:'EXPIRE',  duration:6, scale:1.0,  barDir:'empty', cue:'Expire doucement\nRelâche les tensions dans l\'étirement', beltLed:'#3DD68C', beltLabel:'LED verte' },
];
const COHERENCE5 = () => [
  { id:'inspire', label:'INSPIRE 5s', duration:5, scale:1.42, barDir:'fill',  cue:'Inspire par le nez\nVentre puis poitrine',       beltLed:'#8BA7FF', beltLabel:'LED bleue' },
  { id:'expire',  label:'EXPIRE 5s',  duration:5, scale:1.0,  barDir:'empty', cue:'Expire par la bouche\nLaisser aller',            beltLed:'#F0A040', beltLabel:'LED orange' },
];

/* ── Exercise factory ── */
const mkEx = (s) => {
  const catDefaults = {
    lower_body: { phases: IE(3,2), steps: ['Prends la position de départ, dos neutre', 'INSPIRE — descends le mouvement, périnée relâché', 'EXPIRE — remonte en contractant, périnée qui remonte', 'Reviens à la position initiale avec contrôle'], errors: ['Ne bloque jamais la respiration', 'Périnée actif pendant l\'effort', 'Dos neutre, regard devant'] },
    upper_body: { phases: IE(2,2), steps: ['Position correcte, dos droit, abdos légers', 'INSPIRE — prépare ou descends le mouvement', 'EXPIRE — effectue l\'effort, rentre le ventre', 'Contrôle le retour à la position initiale'], errors: ['Expire à l\'effort', 'Épaules relâchées loin des oreilles', 'Pas d\'élan, geste contrôlé'] },
    perineum:   { phases: KEGEL(3,3), steps: ['Position allongée ou assise, corps détendu', 'Identifie les muscles périnéaux', 'CONTRACTE progressivement, comme pour retenir les urines', 'RELÂCHE complètement, descente consciente'], errors: ['Ne retiens pas la respiration', 'Ne serre pas les fessiers', 'Relâchement aussi important que la contraction'] },
    breathing:  { phases: COHERENCE5(), steps: ['Position confortable, dos soutenu, yeux fermés', 'INSPIRE par le nez — ventre qui se gonfle d\'abord', 'EXPIRE par la bouche — vidage progressif', 'Cycle régulier, sans forçage'], errors: ['Épaules relâchées', 'Rythme régulier', 'Inspire par le nez, expire par la bouche'] },
    core:       { phases: IE(3,3), steps: ['Position gainage, corps aligné de la tête aux pieds', 'INSPIRE — léger gonflement ventral', 'EXPIRE — rentre le ventre, remonte le périnée, maintiens', 'Respire régulièrement, jamais d\'apnée'], errors: ['Ne retiens jamais la respiration', 'Corps parfaitement aligné', 'Périnée actif pendant la tenue'] },
    vacuum:     { phases: VACUUM_P(), steps: ['Debout ou à genoux, dos droit', 'EXPIRE TOTAL — vide complètement les poumons', 'ASPIRE — rentre le ventre sous les côtes sans inspirer', 'RELÂCHE — inspire doucement, ventre qui revient'], errors: ['Jamais en apnée trop longue au début', 'Périnée neutre (ni contracté ni poussé)', 'Commence par 3-5 secondes, progresse'] },
    stretching: { phases: STRETCH_P(), steps: ['Prends la position d\'étirement initiale', 'INSPIRE — allonge le corps, crée de l\'espace', 'EXPIRE — approfondis doucement l\'étirement', 'Maintiens 30-60 secondes en respirant normalement'], errors: ['Jamais de douleur aiguë', 'Pas de rebond dans l\'étirement', 'Progression lente et régulière'] },
  };
  const def = catDefaults[s.cat] || catDefaults.lower_body;
  const periSync = s.periSync || 0;
  return {
    id: s.id, category: s.cat, name: s.name, emoji: s.emoji, diff: s.diff,
    muscles: s.muscles, sets: s.sets, reps: s.reps, restSec: s.diff==='hard'?90:s.diff==='medium'?60:45,
    duration: s.dur || '~12 min',
    periSync,
    profileRestriction: s.restrict || [],
    description: s.desc || `${s.name} — guidage respiratoire et périnéal intégré.`,
    phases: s.phases || def.phases,
    steps: s.steps || def.steps,
    errors: s.errors || def.errors,
    youtubeId: s.ytId || '',
    unsplashKeyword: s.unsplash || `${s.cat},fitness`,
    beltFeedback: periSync >= 2
      ? 'Synchronisation périnée ESSENTIELLE — Ceinture en mode actif ♡♡'
      : periSync === 1
      ? 'Synchronisation périnée recommandée ♡ — Ceinture guide la respiration'
      : 'Guidage respiratoire automatique — Ceinture suit chaque cycle',
  };
};

