export const EXERCISES = RAW.map(mkEx);

export const getExerciseById = (id) => EXERCISES.find(e => e.id === id);
export const getByCategory   = (cat) => EXERCISES.filter(e => e.category === cat);
export const getCategoryMeta = (cat) => CATEGORIES.find(c => c.id === cat);
